config.script:
try:
	self.session.custom.presence.policy = "strict"
except:
	self.session.custom.presence = {"policy": "strict"}
# Screen-scoped cell guard (2026-07-08): session.custom.cell is shared across process
# screens - a cell picked elsewhere (e.g. a die-cast machine) must not leak into this
# screen. Clear it unless it is one of THIS terminal's Die Cast Machine context cells.
try:
	cells = BlueRidge.Location.Terminal.getContextCellsForDropdown(self.session.custom.terminal.terminalLocationId, "Die Cast Machine")
	ids = [c.get("value") for c in cells]
	c = self.session.custom.cell
	if c and c.get("locationId") not in ids:
		self.session.custom.cell = {"locationId": None, "code": "", "name": ""}
except:
	pass
